import { Pagination as ArkPagination } from "@ark-ui/react/pagination";
import {
  FiChevronLeft,
  FiChevronRight,
  FiMoreHorizontal,
} from "react-icons/fi";
import { tv } from "tailwind-variants";

import { cn } from "@/lib/utils";
import { Button } from "@/registry/thornberry/components/button";

import type { ComponentProps } from "react";

const paginationVariants = tv({
  slots: {
    root: "flex w-full flex-col",
    ellipsis: "flex h-9 w-9 items-center justify-center",
    item: "flex h-9 w-9 items-center justify-center rounded-md border border-input bg-background font-medium text-sm hover:bg-muted data-[selected]:border-primary data-[selected]:bg-primary data-[selected]:text-primary-foreground",
    trigger: "h-9 w-9",
  },
});

const { root, ellipsis, item, trigger } = paginationVariants();

const PaginationProvider = ArkPagination.RootProvider;
const PaginationContext = ArkPagination.Context;

const PaginationRoot = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.Root>) => (
  <ArkPagination.Root className={cn(root(), className)} {...rest} />
);

const PaginationEllipsis = ({
  className,
  index,
  ...rest
}: ComponentProps<typeof ArkPagination.Ellipsis>) => (
  <ArkPagination.Ellipsis
    index={index}
    className={cn(ellipsis(), className)}
    {...rest}
  >
    <FiMoreHorizontal className="h-4 w-4" />
  </ArkPagination.Ellipsis>
);

const PaginationItem = ({
  className,
  page,
  ...rest
}: ComponentProps<typeof ArkPagination.Item> & { page?: number }) => (
  <ArkPagination.Item className={cn(item(), className)} {...rest} />
);

const PaginationPrevTrigger = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.PrevTrigger>) => (
  <ArkPagination.PrevTrigger asChild {...rest}>
    <Button variant="outline" size="icon" className={cn(trigger(), className)}>
      <FiChevronLeft className="h-4 w-4" />
    </Button>
  </ArkPagination.PrevTrigger>
);

const PaginationNextTrigger = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.NextTrigger>) => (
  <ArkPagination.NextTrigger asChild {...rest}>
    <Button variant="outline" size="icon" className={cn(trigger(), className)}>
      <FiChevronRight className="h-4 w-4" />
    </Button>
  </ArkPagination.NextTrigger>
);

export {
  PaginationRoot,
  PaginationItem,
  PaginationEllipsis,
  PaginationPrevTrigger,
  PaginationNextTrigger,
  PaginationProvider,
  PaginationContext,
};

import { ark } from "@ark-ui/react";
import { tv } from "tailwind-variants";

import { cn } from "@/lib/utils";

import type { ComponentProps } from "react";
import type { VariantProps } from "tailwind-variants";

const buttonVariants = tv({
  base: "inline-flex shrink-0 cursor-pointer items-center justify-center gap-2 whitespace-nowrap rounded-md font-medium text-sm outline-none transition-all focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  variants: {
    variant: {
      solid: "bg-primary text-primary-foreground shadow-xs hover:bg-primary/90",
      outline:
        "border bg-background text-base-950 shadow-xs dark:border-input dark:bg-input/20 dark:text-base-50 dark:hover:bg-input/30",
      muted: "bg-muted text-muted-foreground shadow-xs hover:bg-muted/80",
      ghost:
        "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
      link: "text-primary underline-offset-4 hover:underline",
    },
    size: {
      sm: "h-8 gap-1.5 rounded-md px-3 has-[>svg]:px-2.5",
      md: "h-9 px-4 py-2 has-[>svg]:px-3",
      lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
      icon: "size-9",
    },
  },
  defaultVariants: {
    variant: "solid",
    size: "md",
  },
});

const Button = ({
  className,
  variant,
  size,
  ...rest
}: ComponentProps<typeof ark.button> & VariantProps<typeof buttonVariants>) => (
  <ark.button
    type="button"
    className={cn(buttonVariants({ variant, size }), className)}
    {...rest}
  />
);

export { Button, buttonVariants };

import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

import type { ClassValue } from "clsx";

export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};
